namespace sv_d4c6bfaad3154c44981baac09e74ded1.Models;

public class WizardData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = new();
    public List<ReferenceContact> References { get; set; } = new();

    /// <summary>Tracks highest completed step (1-based). 0 means none completed.</summary>
    public int CompletedStep { get; set; }
}

public class PersonalInfo
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class ExperienceEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_d4c6bfaad3154c44981baac09e74ded1.Models;

namespace sv_d4c6bfaad3154c44981baac09e74ded1.Services;

/// <summary>
/// Singleton, in-memory store keyed by session cookie.
/// Each user gets their own WizardData instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_d4c6bfaad3154c44981baac09e74ded1.Services.WizardStateStore Store

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-progress px-4 py-3">
            <h5 class="mb-2">Job Application — Step @CurrentStep of 4</h5>
            <div class="d-flex gap-2 mb-2">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var css = step == CurrentStep ? "btn-primary"
                            : step <= CompletedStep ? "btn-success"
                            : "btn-outline-secondary";
                    <a href="@StepUrl(step)" class="btn btn-sm @css">@StepLabel(step)</a>
                }
            </div>
            <div class="progress" style="height: 6px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(CurrentStep * 25)%"></div>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private int CurrentStep;
    private int CompletedStep;

    protected override void OnInitialized()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        CurrentStep = path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience"    => 2,
            "/apply/references"    => 3,
            "/apply/review"        => 4,
            _ => 1
        };

        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"];
        CompletedStep = sessionId is not null ? Store.GetOrCreate(sessionId).CompletedStep : 0;
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

