using System.Collections.Concurrent;
using sv_d4c6bfaad3154c44981baac09e74ded1.Models;

namespace sv_d4c6bfaad3154c44981baac09e74ded1.Services;

/// <summary>
/// Singleton, in-memory store keyed by session cookie.
/// Each user gets their own WizardData instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

