@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer
@inject sv_d4c6bfaad3154c44981baac09e74ded1.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Personal Info — Apply</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="Model" OnValidSubmit="Next" FormName="personal-info">
    <DataAnnotationsValidator />
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private string _sessionId = default!;
    private Models.PersonalInfo Model { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = Store.GetOrCreate(_sessionId);
            // Deep-copy so edits don't mutate store until save
            Model = new Models.PersonalInfo
            {
                Name = data.PersonalInfo.Name,
                Email = data.PersonalInfo.Email
            };
        }
    }

    private void Next()
    {
        if (string.IsNullOrEmpty(_sessionId)) return;
        var data = Store.GetOrCreate(_sessionId);
        data.PersonalInfo.Name = Model.Name;
        data.PersonalInfo.Email = Model.Email;
        if (data.CompletedStep < 1) data.CompletedStep = 1;
        Nav.NavigateTo("/apply/experience", forceLoad: true);
    }
}

