@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer
@inject sv_d4c6bfaad3154c44981baac09e74ded1.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Experience — Apply</PageTitle>

<h3>Step 2: Work Experience</h3>

@if (Entries.Count == 0)
{
    <p class="text-muted">No entries yet. Add your first job below.</p>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var idx = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Entry @(idx + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(idx)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Entries[idx].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="Entries[idx].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Entries[idx].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary me-2" @onclick="AddEntry">+ Add Entry</button>

<hr />
<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _sessionId = default!;
    private List<Models.ExperienceEntry> Entries { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = Store.GetOrCreate(_sessionId);
            Entries = data.Experience
                .Select(e => new Models.ExperienceEntry { Company = e.Company, Title = e.Title, Years = e.Years })
                .ToList();
        }
    }

    private void AddEntry() => Entries.Add(new Models.ExperienceEntry());
    private void RemoveEntry(int idx) => Entries.RemoveAt(idx);

    private void Next()
    {
        if (string.IsNullOrEmpty(_sessionId)) return;
        var data = Store.GetOrCreate(_sessionId);
        data.Experience = Entries
            .Select(e => new Models.ExperienceEntry { Company = e.Company, Title = e.Title, Years = e.Years })
            .ToList();
        if (data.CompletedStep < 2) data.CompletedStep = 2;
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }
}

@page "/apply/references"
@layout WizardLayout
@rendermode InteractiveServer
