    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Reference @(idx + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(idx)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="Refs[idx].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" @bind="Refs[idx].Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="Refs[idx].Relationship" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary me-2" @onclick="AddRef">+ Add Reference</button>

<hr />
<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _sessionId = default!;
    private List<Models.ReferenceContact> Refs { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = Store.GetOrCreate(_sessionId);
            Refs = data.References
                .Select(r => new Models.ReferenceContact { Name = r.Name, Email = r.Email, Relationship = r.Relationship })
                .ToList();
        }
    }

    private void AddRef() => Refs.Add(new Models.ReferenceContact());
    private void RemoveRef(int idx) => Refs.RemoveAt(idx);

    private void Next()
    {
        if (string.IsNullOrEmpty(_sessionId)) return;
        var data = Store.GetOrCreate(_sessionId);
        data.References = Refs
            .Select(r => new Models.ReferenceContact { Name = r.Name, Email = r.Email, Relationship = r.Relationship })
            .ToList();
        if (data.CompletedStep < 3) data.CompletedStep = 3;
        Nav.NavigateTo("/apply/review", forceLoad: true);
    }
}

@page "/apply/review"
@layout WizardLayout
@rendermode InteractiveServer
@inject sv_d4c6bfaad3154c44981baac09e74ded1.Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Review — Apply</PageTitle>

<h3>Step 4: Review Your Application</h3>

@if (Data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @Data.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @Data.PersonalInfo.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (Data.Experience.Count == 0)
        {
            <p class="text-muted">No entries provided.</p>
        }
        @foreach (var exp in Data.Experience)
        {
            <div class="mb-2 ps-3 border-start">
                <p class="mb-0"><strong>@exp.Title</strong> at @exp.Company (@exp.Years years)</p>
            </div>
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (Data.References.Count == 0)
        {
            <p class="text-muted">No references provided.</p>
        }
        @foreach (var r in Data.References)
        {
            <div class="mb-2 ps-3 border-start">
                <p class="mb-0"><strong>@r.Name</strong> — @r.Email (@r.Relationship)</p>
            </div>
        }
    </div>

    <hr />
    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-secondary">← Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">
            Your application has been submitted successfully!
        </div>
    }
}

@code {
    private string _sessionId = default!;
    private Models.WizardData? Data;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        if (!string.IsNullOrEmpty(_sessionId))
        {
            Data = Store.GetOrCreate(_sessionId);
        }
    }

    private void Submit()
    {
        _submitted = true;
        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = Store.GetOrCreate(_sessionId);
            if (data.CompletedStep < 4) data.CompletedStep = 4;
        }
    }
}

