    if (!context.Request.Cookies.ContainsKey("WizardSession"))
    {
        context.Response.Cookies.Append("WizardSession", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            IsEssential = true,
            MaxAge = TimeSpan.FromHours(4)
        });
    }
    await next();
});

